import java.io.IOException;
import java.io.PrintWriter;
import org.owasp.encoder.Encode;

public class XssSecureCode {

    public static void main(String[] args) throws IOException {
        // Simulating user input received from a form submission
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Properly handling user input by encoding it before embedding in HTML response
        PrintWriter out = new PrintWriter("response.html");
        out.println("<html>");
        out.println("<head><title>XSS Secure Example</title></head>");
        out.println("<body>");
        out.println("<h1>Welcome, " + Encode.forHtml(userInput) + "</h1>"); // Encoded user input to prevent XSS
        out.println("</body>");
        out.println("</html>");

        out.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
